changeSet.sql:
-- Add columns as nullable first
ALTER TABLE channel ADD COLUMN IF NOT EXISTS last_event_at TIMESTAMPTZ;
ALTER TABLE channel ADD COLUMN IF NOT EXISTS is_stale BOOLEAN;

-- Set default value for existing rows
UPDATE channel SET is_stale = false WHERE is_stale IS NULL;

-- Now make it NOT NULL with default
ALTER TABLE channel ALTER COLUMN is_stale SET NOT NULL;
ALTER TABLE channel ALTER COLUMN is_stale SET DEFAULT false;

COMMENT ON COLUMN channel.last_event_at IS 'Timestamp of the most recent event in this channel';
COMMENT ON COLUMN channel.is_stale IS 'Flag indicating if channel has not received events recently';
COMMENT ON INDEX idx_channel_is_stale IS 'Partial index for filtering stale channels';
COMMENT ON INDEX idx_channel_last_event_at IS 'Index for sorting channels by last event time';

DROP TRIGGER IF EXISTS trg_update_channel_last_event ON event;

CREATE TRIGGER trg_update_channel_last_event
AFTER INSERT
ON event
FOR EACH ROW
EXECUTE FUNCTION update_channel_last_event();
